import os
import uuid
import smtplib
from email.mime.text import MIMEText
from flask import Flask, request, jsonify

app = Flask(__name__)

# --- Configuration (replace with your actual values) ---
app.config['SECRET_KEY'] = os.environ.get('FLASK_SECRET_KEY', 'your_super_secret_key_here')
app.config['MAIL_SERVER'] = os.environ.get('MAIL_SERVER', 'smtp.mailtrap.io')
app.config['MAIL_PORT'] = int(os.environ.get('MAIL_PORT', 2525))
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME', 'your_mailtrap_username')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD', 'your_mailtrap_password')
app.config['MAIL_SENDER'] = os.environ.get('MAIL_SENDER', 'no-reply@yourdomain.com')
app.config['RESET_PASSWORD_BASE_URL'] = os.environ.get('RESET_PASSWORD_BASE_URL', 'http://localhost:3000/reset-password')

# --- Mock Database (replace with a real DB like SQLAlchemy for production) ---
# This dictionary will store user data and password reset tokens.
# In a real application, you'd use a proper database.
MOCK_DB = {
    "users": {
        "user@example.com": {"id": 1, "username": "TestUser", "password_hash": "hashed_password_here"},
        "another@example.com": {"id": 2, "username": "AnotherUser", "password_hash": "another_hashed_password"},
    },
    "password_reset_tokens": {} # token: {"user_email": "...", "expires_at": "..."}
}

def send_email(to_email, subject, body):
    """Sends an email using the configured SMTP server."""
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = app.config['MAIL_SENDER']
    msg['To'] = to_email

    try:
        with smtplib.SMTP(app.config['MAIL_SERVER'], app.config['MAIL_PORT']) as server:
            server.login(app.config['MAIL_USERNAME'], app.config['MAIL_PASSWORD'])
            server.send_message(msg)
        return True
    except Exception as e:
        print(f"Error sending email: {e}")
        return False

@app.route('/password/reset', methods=['POST'])
def request_password_reset():
    """
    Endpoint to request a password reset.
    Receives user email, generates a token, stores it, and sends a reset link.
    """
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({"message": "Email is required"}), 400

    # 1. Check if user exists (in a real app, this would query your user table)
    if email not in MOCK_DB["users"]:
        # For security, often you don't confirm if the email exists.
        # Just send a generic success message or log the attempt.
        # For this MVP, we'll confirm existence.
        return jsonify({"message": "If an account with that email exists, a password reset link has been sent."}), 200

    # 2. Generate a unique token
    token = str(uuid.uuid4())

    # 3. Store the token with the user's email (and optionally an expiration timestamp)
    # For MVP, no expiration, but add it for production!
    MOCK_DB["password_reset_tokens"][token] = {"user_email": email}
    print(f"Generated token for {email}: {token}") # For debugging

    # 4. Construct the reset link
    reset_link = f"{app.config['RESET_PASSWORD_BASE_URL']}?token={token}"

    # 5. Send the email
    subject = "Password Reset Request"
    body = (
        f"Hi,\n\nYou have requested to reset your password. "
        f"Please click on the following link to reset your password:\n\n"
        f"{reset_link}\n\n"
        f"If you did not request a password reset, please ignore this email.\n"
        f"This link will expire soon (not implemented yet in MVP, but will be!)."
    )

    if send_email(email, subject, body):
        return jsonify({"message": "Password reset link sent to your email."}), 200
    else:
        # In a real app, you might log this error more rigorously
        return jsonify({"message": "Failed to send password reset email. Please try again later."}), 500

